import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTimeAxis } from "./OjTimeAxis";
export { OjTimeAxis };

/**
 * Create an instance of [[OjTimeAxis]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTimeAxis(driver, By.id('my-oj-time-axis'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTimeAxis(driver: DriverLike, by: By): Promise<OjTimeAxis> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTimeAxis
  if (!(webEl instanceof OjTimeAxis)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-time-axis>`);
  }
  return webEl;
}

register("oj-time-axis", OjTimeAxis);
